	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

const (
	StatusExecutionFailed            = "execution_failed"
	StatusLandConflict               = "land_conflict"
	StatusSuccess                    = "success"
	StatusNoChanges                  = "no_changes"
	StatusAlreadySatisfied           = "already_satisfied"
	StatusPushFailed                 = "push_failed"
	StatusPushConflict               = "push_conflict"
	StatusDeclinedNeedsDecomposition = "declined_needs_decomposition"
)

const (
	PushFailedReasonPrefix   = "landed locally; push failed:"
	PushConflictReasonPrefix = "landed locally; push conflict:"
)

type Report struct {
	BeadID                      string
	AttemptID                   string
	WorkerID                    string
	Harness                     string
	Provider                    string
	Model                       string
	ActualPower                 int
	Status                      string
	Detail                      string
	SessionID                   string
	BaseRev                     string
	ResultRev                   string
	PreserveRef                 string
	RetryAfter                  string
	NoChangesRationale          string
	ReviewVerdict               string
	ReviewRationale             string
	Tier                        string
	ProbeResult                 string
	CostUSD                     float64
	DurationMS                  int64
	RequestedProfile            string
	RequestedTier               string
	ResolvedTier                string
	EscalationCount             int
	FinalTier                   string
	DecompositionRecommendation []string
	DecompositionRationale      string
	Disrupted                   bool
	DisruptionReason            string
	OutcomeReason               string
	Error                       string
	Stderr                      string
	RateLimitBudget             time.Duration
}

type Executor interface {
	Execute(ctx context.Context, beadID string) (Report, error)
}

type ExecutorFunc func(ctx context.Context, beadID string) (Report, error)

func (f ExecutorFunc) Execute(ctx context.Context, beadID string) (Report, error) {
	return f(ctx, beadID)
}

type Store interface {
	AppendEvent(beadID string, ev bead.BeadEvent) error
	CloseWithEvidence(beadID, sessionID, sha string) error
	Unclaim(beadID string) error
	SetExecutionCooldown(beadID string, until time.Time, status, detail string) error
	IncrNoChangesCount(beadID string) (int, error)
}

type ConflictAutoRecoverFn func(wd, preserveRef string) (string, error)

type ConflictResolverFn func(ctx context.Context, beadID, preserveRef, projectRoot string) (newTip string, isBlocking bool, err error)

type AttemptOpts struct {
	Bead                   bead.Bead
	Executor               Executor
	Store                  Store
	ProjectRoot            string
	SatisfactionChecker    SatisfactionChecker
	VerificationRunner     VerificationCommandRunner
	AutoRecover            ConflictAutoRecoverFn
	ConflictResolver       ConflictResolverFn
	Assignee               string
	Now                    func() time.Time
	Cooldown               time.Duration
	RateLimitBudget        time.Duration
	RateLimitPerWaitCap    time.Duration
	RateLimitWaitEvaluator func(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision
	RateLimitSleep         func(ctx context.Context, d time.Duration) error
	RateLimitNow           func() time.Time
	RateLimitOnRetry       func(ctx context.Context, info RateLimitRetryInfo)
}

type Disposition string

const (
	OutcomeReported Disposition = "reported"
	OutcomeSuccess  Disposition = "merged"
	OutcomePark     Disposition = "park"
)

type Outcome struct {
	Report      Report
	Disposition Disposition
	NoChanges   *NoChangesOutcome
	Parking     *ParkingOutcome
	StoreErrOp  string
	StoreErr    error
}

// ParkingOutcome carries the structured instructions for outcomes that must
// be parked instead of retried immediately.
type ParkingOutcome struct {
	Unclaim              bool
	RetryAfter           time.Time
	RunPostAttemptTriage bool
	Event                *ParkingEvent
}

// ParkingEvent is the event template returned by Attempt for structured park
// outcomes. The execute loop converts it into a bead.BeadEvent when it applies
// the parking instructions.
type ParkingEvent struct {
	Kind    string
	Summary string
	Body    string
}

func Attempt(ctx context.Context, store Store, beadID string, opts AttemptOpts) (Outcome, error) {
	if opts.Executor == nil {
		return Outcome{}, fmt.Errorf("try attempt: executor is required")
	}
	rateCfg := resolveRateLimitRetryConfig(opts)
	var (
		report Report
		err    error
	)
	for retryCount, elapsed := 0, time.Duration(0); ; {
		report, err = opts.Executor.Execute(ctx, beadID)
		if err != nil {
			report = Report{
				BeadID: beadID,
				Status: StatusExecutionFailed,
				Detail: err.Error(),
				Error:  err.Error(),
			}
		}
		if report.BeadID == "" {
			report.BeadID = beadID
		}
		if report.Status == "" {
			report.Status = StatusExecutionFailed
		}

		rateLimited := IsRateLimitReport(&report)
		effectiveBudget := rateCfg.Budget
		if opts.RateLimitBudget == 0 && report.RateLimitBudget != 0 {
			effectiveBudget = report.RateLimitBudget
		}
		decision, retryAfter := evaluateRateLimitAttempt(report, rateCfg, retryCount+1, elapsed, effectiveBudget)
		if !decision.ShouldRetry {
			if decision.Reason != "" {
				report.Error = decision.Reason
			}
			if rateLimited && decision.Reason != "" && rateCfg.OnRetry != nil {
				rateCfg.OnRetry(ctx, RateLimitRetryInfo{
					Attempt:    retryCount + 1,
					Source:     decision.Source,
					Report:     &report,
					Elapsed:    elapsed,
					RetryAfter: retryAfter,
					OverBudget: true,
				})
			}
			break
		}

		retryCount++
		info := RateLimitRetryInfo{
			Attempt:    retryCount,
			Wait:       decision.Wait,
			Source:     decision.Source,
			Report:     &report,
			Elapsed:    elapsed,
			RetryAfter: retryAfter,
		}
		if rateCfg.OnRetry != nil {
			rateCfg.OnRetry(ctx, info)
		}
		if err := rateCfg.Sleep(ctx, decision.Wait); err != nil {
			return Outcome{}, err
		}
		elapsed += decision.Wait
	}

	if ShouldAttemptConflictRecovery(report, opts.ProjectRoot) {
		if opts.Store == nil {
			opts.Store = store
		}
		return ConflictRecoveryOutcome(ctx, ConflictRecoveryInput{
			Bead:             opts.Bead,
			Report:           report,
			ProjectRoot:      opts.ProjectRoot,
			AutoRecover:      opts.AutoRecover,
			ConflictResolver: opts.ConflictResolver,
			Store:            opts.Store,
			Assignee:         opts.Assignee,
			Now:              opts.Now,
			Cooldown:         opts.Cooldown,
		}), err
	}

	if report.Status == StatusNoChanges {
		if opts.Store == nil {
			opts.Store = store
		}
		if opts.Store == nil {
			return Outcome{Report: report, StoreErrOp: "IncrNoChangesCount", StoreErr: fmt.Errorf("try attempt: no_changes store is required")}, nil
		}
		noChangesCount, countErr := opts.Store.IncrNoChangesCount(beadID)
		if countErr != nil {
			return Outcome{Report: report, StoreErrOp: "IncrNoChangesCount", StoreErr: countErr}, nil
		}
		noChangesOut, adjudicatedReport, adjErr := adjudicateNoChangesContract(ctx, beadID, report, opts.ProjectRoot, noChangesCount, opts.SatisfactionChecker, opts.VerificationRunner)

					Source:    "ddx agent execute-loop",
					CreatedAt: now().UTC(),
				})
			}
			if noChanges.Label != "" {
				if lerr := addBeadLabel(w.Store, candidate.ID, noChanges.Label); lerr != nil {
					if w.handleOutcomeStoreError(ctx, candidate.ID, "addBeadLabel", lerr, assignee, result, runtime, now) {
						continue
					}
					return result, ctx.Err()
				}
			}
			if noChanges.Satisfied {
				// Adjudication confirmed bead is already satisfied.
				// Set the terminal status BEFORE the close so the late
				// executeBeadLoopEvent append captures "already_satisfied"
				// (not "no_changes"), and emit an early execute-bead
				// evidence event so the closure gate accepts even when
				// BaseRev is empty (test fixtures and genuinely-no-commit
				// satisfied beads).
				report.Status = ExecuteBeadStatusAlreadySatisfied
				if noChanges.Evidence != "" {
					// Checker evidence explains why the bead is being closed;
					// it takes precedence over the executor's attempt detail.
					report.Detail = noChanges.Evidence
				}
				_ = w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC()))
				if cerr := w.Store.CloseWithEvidence(candidate.ID, report.SessionID, report.BaseRev); cerr != nil {
					if w.handleOutcomeStoreError(ctx, candidate.ID, "CloseWithEvidence", cerr, assignee, result, runtime, now) {
						continue
					}
					return result, ctx.Err()
				}
				result.Successes++
				result.LastSuccessAt = now().UTC()
			} else {
				// Unresolved: suppress immediate retry so the queue can
				// move on to other beads.
				report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
				if shouldSuppressNoProgress(report) {
					retryAfter := now().UTC().Add(CapLoopCooldown(noProgressCooldown))
					if cerr := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail); cerr != nil {
						if w.handleOutcomeStoreError(ctx, candidate.ID, "SetExecutionCooldown", cerr, assignee, result, runtime, now) {
							continue
						}
						return result, ctx.Err()
					}
					report.RetryAfter = retryAfter.Format(time.RFC3339)
				}
				result.Failures++
				result.LastFailureStatus = report.Status
			}
		} else {
			if attemptOut.Parking == nil && attemptOut.Disposition != agenttry.OutcomePark {
				if err := w.Store.Unclaim(candidate.ID); err != nil {
					if w.handleOutcomeStoreError(ctx, candidate.ID, "Unclaim", err, assignee, result, runtime, now) {
						continue
					}
					return result, ctx.Err()
				}
			}
			if report.Status == ExecuteBeadStatusPreservedNeedsReview {
				if err := w.Store.AppendNotes(candidate.ID, preservedNeedsReviewNote(report)); err != nil {
					if w.handleOutcomeStoreError(ctx, candidate.ID, "AppendNotes", err, assignee, result, runtime, now) {
						continue
					}
					return result, ctx.Err()
				}
				result.Failures++
				result.LastFailureStatus = report.Status
			} else {
				report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
				if shouldSuppressNoProgress(report) {
					retryAfter := now().UTC().Add(CapLoopCooldown(noProgressCooldown))
					if err := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail); err != nil {
						if w.handleOutcomeStoreError(ctx, candidate.ID, "SetExecutionCooldown", err, assignee, result, runtime, now) {
							continue
						}
						return result, ctx.Err()
					}
					report.RetryAfter = retryAfter.Format(time.RFC3339)
				}
				result.Failures++
				result.LastFailureStatus = report.Status
			}
		}

		result.Results = append(result.Results, report)

		// Skip the late execute-bead append for already-satisfied beads —
		// the satisfied path appends its own terminal event before
		// CloseWithEvidence so the closure gate sees execution evidence.
		// Duplicating it here would yield two identical events.
		if report.Status != ExecuteBeadStatusAlreadySatisfied {
			if err := w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC())); err != nil {
				// Event recording failure is non-terminal: log it and continue.
				// result counters were already updated by the outcome block above;
				// do not double-count by calling handleOutcomeStoreError.
				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "outcome store error (AppendEvent %s): %v (continuing)\n", candidate.ID, err)
				}
				if ctx.Err() == nil {
					_ = w.Store.SetExecutionCooldown(candidate.ID, now().UTC().Add(StoreErrorCooldown), "loop-error", "AppendEvent: "+err.Error())
				}
				if ctx.Err() != nil {
					return result, ctx.Err()
				}
				continue
			}
		}

		// Emit terminal progress phase event.
		terminalPhase := "failed"
		if report.Status == ExecuteBeadStatusSuccess || report.Status == ExecuteBeadStatusAlreadySatisfied {
			terminalPhase = "done"
		} else if report.PreserveRef != "" {
			terminalPhase = "preserved"
		}
		// Use the real attempt_id from the report if available.
		finalAttemptID := report.AttemptID
		if finalAttemptID == "" {
			finalAttemptID = provAttemptID
		}
		phaseSeq++
		emitProgress(runtime.ProgressCh, ProgressEvent{
			EventID:   "evt-" + randomProgressID(),
			AttemptID: finalAttemptID,
			WorkerID:  runtime.WorkerID,
			ProjectID: runtime.ProjectRoot,
			BeadID:    candidate.ID,
			Harness:   harness,
			Model:     model,
			Profile:   profile,
			Phase:     terminalPhase,
			PhaseSeq:  phaseSeq,
			Heartbeat: false,
			TS:        now().UTC(),
			ElapsedMS: now().Sub(runStart).Milliseconds(),
			Message:   report.Detail,
		})

		emit("bead.result", map[string]any{
			"bead_id":              candidate.ID,
			"status":               report.Status,
			"detail":               report.Detail,
			"session_id":           report.SessionID,
			"result_rev":           report.ResultRev,
			"base_rev":             report.BaseRev,
			"preserve_ref":         report.PreserveRef,
			"no_changes_rationale": report.NoChangesRationale,
			"duration_ms":          now().Sub(runStart).Milliseconds(),
		})

		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "✓ %s → %s\n", candidate.ID, formatLoopResult(report))
		}

		if runtime.Once {
			exitReason = "once_complete"
			return result, nil
		}
	}
}

// emitPickerPrioritySkips fires a picker.priority_skip event when the picker
// chose `chosen` while at least one strictly higher-priority bead was passed
// over (ddx-9d55601f AC #4). Skips at the same priority as `chosen` are NOT
// reported — those are FIFO order or label-filter siblings, not starvation.
//
// The emit is guarded so it costs nothing when the chosen bead is the highest-
// priority bead the picker saw (the common case).
func emitPickerPrioritySkips(emit func(string, map[string]any), chosen bead.Bead, skips []pickerSkip) {
	if len(skips) == 0 {
		return
	}
	var higher []map[string]any
	for _, s := range skips {
		if s.Priority < chosen.Priority {
			higher = append(higher, map[string]any{
				"bead_id":  s.BeadID,
				"priority": s.Priority,
				"reason":   s.Reason,
			})
		}
	}
	if len(higher) == 0 {
		return
	}
	emit("picker.priority_skip", map[string]any{
		"chosen_bead_id":  chosen.ID,
		"chosen_priority": chosen.Priority,
		"skipped":         higher,
	})
}

// pickerSkip records a single bead that the picker passed over while looking
// for the next candidate. It is used to emit a structured picker.priority_skip
// event when a worker claims a lower-priority bead while a higher-priority
// bead was skipped, so future starvation regressions are observable.
//
// Reason values are bounded to the set named in ddx-9d55601f AC #4:
//
//	label_filter, in_attempted, claim_race, eligibility_filter, retry_cooldown
//
// Note: eligibility_filter and retry_cooldown are applied upstream in
// Store.ReadyExecution (so beads filtered for those reasons never reach

	// be delivered in a single pass — typically because the scope is
	// epic-sized and must first be broken into sub-beads. It is distinct
	// from no_changes (which means "I tried and there was nothing to change")
	// and from execution_failed (which means the agent or harness errored).
	//
	// The loop treats this status as terminal-for-loop: it parks the bead
	// with a long cooldown and records the recommended sub-beads as a
	// structured `decomposition-recommendation` event. No further attempts
	// happen until an operator clears the cooldown (e.g. via
	// `ddx bead cooldown clear`) or splits the bead.
	ExecuteBeadStatusDeclinedNeedsDecomposition = "declined_needs_decomposition"

	// Post-merge review outcomes. The bead was merged, then reviewed;
	// the review returned a non-APPROVE verdict and the bead was reopened.
	ExecuteBeadStatusReviewRequestChanges = "review_request_changes"
	ExecuteBeadStatusReviewBlock          = "review_block"
	ExecuteBeadStatusReviewMalfunction    = "review_malfunction"

	// ExecuteBeadStatusLandConflictUnresolvable is set when execute-loop
	// attempted 3-way ort auto-resolution and (if configured) a focused
	// conflict-resolve agent run for a preserved iteration, and both failed.
	// The bead is parked under LandConflictCooldown for operator review.
	ExecuteBeadStatusLandConflictUnresolvable = "land_conflict_unresolvable"

	// ExecuteBeadStatusLandConflictNeedsHuman is set when the focused
	// conflict-resolve agent escalated to BLOCKING — the conflict requires
	// human judgment, not automated retry. Parked under the same short
	// cooldown with a kind:land-conflict-needs-human event.
	ExecuteBeadStatusLandConflictNeedsHuman = "land_conflict_needs_human"
)

// ClassifyExecuteBeadStatus maps a landing outcome to the supervisor-visible
// status contract. This is called by ApplyLandingToResult and by callers who
// build an ExecuteBeadReport from a landing result.
func ClassifyExecuteBeadStatus(outcome string, exitCode int, reason string) string {
	if exitCode != 0 {
		return ExecuteBeadStatusExecutionFailed
	}

	switch outcome {
	case "merged":
		// A merged outcome whose reason carries the push-failure marker
		// means the local target branch advanced but `git push` rejected the
		// new tip (large blob, branch protection, auth, divergence, etc.).
		// Classify these as push_failed so the loop refuses to close the
		// bead and operators are forced to investigate.
		if strings.HasPrefix(reason, PushConflictReasonPrefix) {
			return ExecuteBeadStatusPushConflict
		}
		if strings.HasPrefix(reason, PushFailedReasonPrefix) {
			return ExecuteBeadStatusPushFailed
		}
		return ExecuteBeadStatusSuccess
	case "no-changes", ExecuteBeadOutcomeTaskNoChanges:
		return ExecuteBeadStatusNoChanges
	case "no-evidence", ExecuteBeadOutcomeTaskNoEvidence:
		return ExecuteBeadStatusNoEvidenceProduced
	case "error":
		return ExecuteBeadStatusExecutionFailed
	case "preserved":
		switch reason {
		case "merge conflict", "merge failed", "ff-merge not possible":
			return ExecuteBeadStatusLandConflict
		case "post-run checks failed":
			return ExecuteBeadStatusPostRunCheckFailed
		case RatchetPreserveReason:
			return ExecuteBeadStatusRatchetFailed
		case OperatorCancelReason:
			return ExecuteBeadStatusPreservedNeedsReview
		default:
			if isPreservedNeedsReviewReason(reason) {
				return ExecuteBeadStatusPreservedNeedsReview
			}
			// Preserved iterations may still be success when the caller
			// explicitly requested no merge.
			return ExecuteBeadStatusSuccess
		}
	case ExecuteBeadOutcomeTaskSucceeded:
		return ExecuteBeadStatusSuccess
	case ExecuteBeadOutcomeTaskFailed:
		return ExecuteBeadStatusExecutionFailed

package try

import (
	"context"
	"encoding/json"
	"fmt"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestAttempt_WrapsLegacyExecutor(t *testing.T) {
	out, err := Attempt(context.Background(), nil, "ddx-test", AttemptOpts{
		Executor: ExecutorFunc(func(ctx context.Context, beadID string) (Report, error) {
			return Report{BeadID: beadID, Status: StatusSuccess, ResultRev: "abc123"}, nil
		}),
	})
	require.NoError(t, err)

	assert.Equal(t, OutcomeReported, out.Disposition)
	assert.Equal(t, "ddx-test", out.Report.BeadID)
	assert.Equal(t, StatusSuccess, out.Report.Status)
	assert.Equal(t, "abc123", out.Report.ResultRev)
}

func TestAttempt_NoChanges_StaysCanonical_NotNeedsInvestigation(t *testing.T) {
	store := &attemptStore{}

	out, err := Attempt(context.Background(), store, "ddx-test", AttemptOpts{
		Store: store,
		Executor: ExecutorFunc(func(ctx context.Context, beadID string) (Report, error) {
			return Report{
				BeadID:             beadID,
				Status:             StatusNoChanges,
				NoChangesRationale: "status: needs_investigation\nreason: provider quota unknown",
			}, nil
		}),
	})
	require.NoError(t, err)

	assert.Equal(t, OutcomeReported, out.Disposition)
	assert.Equal(t, StatusNoChanges, out.Report.Status)
	require.NotNil(t, out.NoChanges)
	assert.False(t, out.NoChanges.Satisfied)
	assert.Equal(t, NoChangesEventNeedsInvestigation, out.NoChanges.EventKind)
	assert.Equal(t, NoChangesLabelNeedsInvestigation, out.NoChanges.Label)
	assert.Contains(t, out.NoChanges.EventBody, "provider quota unknown")
	assert.Equal(t, 1, store.noChangesCountCalls)
}

func TestAttempt_NoChanges_WiresAdjudicateNoChangesContract(t *testing.T) {
	store := &attemptStore{}
	runnerCalls := 0

	out, err := Attempt(context.Background(), store, "ddx-test", AttemptOpts{
		Store: store,
		Executor: ExecutorFunc(func(ctx context.Context, beadID string) (Report, error) {
			return Report{
				BeadID:             beadID,
				Status:             StatusNoChanges,
				NoChangesRationale: "verification_command: true\noutput: passes",
			}, nil
		}),
		VerificationRunner: func(ctx context.Context, projectRoot, command string) (int, string, error) {
			runnerCalls++
			assert.Equal(t, "true", command)
			return 0, "ok", nil
		},
	})
	require.NoError(t, err)

	assert.Equal(t, OutcomeReported, out.Disposition)
	assert.Equal(t, StatusAlreadySatisfied, out.Report.Status)
	require.NotNil(t, out.NoChanges)
	assert.True(t, out.NoChanges.Satisfied)
	assert.Equal(t, NoChangesEventVerified, out.NoChanges.EventKind)
	assert.Empty(t, out.NoChanges.Label)
	assert.Equal(t, 1, runnerCalls)
}

func TestAttempt_ConflictRecovered_ReturnsMergedOutcome(t *testing.T) {
	store := &attemptStore{}
	target := bead.Bead{ID: "ddx-test"}

	out, err := Attempt(context.Background(), store, target.ID, AttemptOpts{
		Bead: target,
		Executor: ExecutorFunc(func(ctx context.Context, beadID string) (Report, error) {
			return Report{
				BeadID:      beadID,
				Status:      StatusLandConflict,
				Detail:      "merge conflict",
				PreserveRef: "refs/ddx/iterations/ddx-test/attempt",
				BaseRev:     "base",
				ResultRev:   "result",
				SessionID:   "session",
			}, nil
		}),
		Store:       store,
		ProjectRoot: t.TempDir(),
		AutoRecover: func(wd, preserveRef string) (string, error) {
			return "merged-tip", nil
		},
		Assignee: "worker",
		Now:      func() time.Time { return time.Date(2026, 5, 4, 1, 2, 3, 0, time.UTC) },
		Cooldown: time.Minute,
	})
	require.NoError(t, err)

	assert.Equal(t, OutcomeSuccess, out.Disposition)
	assert.Equal(t, StatusSuccess, out.Report.Status)
	assert.Equal(t, "merged-tip", out.Report.ResultRev)
	assert.Equal(t, "merged-tip", store.closedSHA)
	require.Len(t, store.events, 1)
	assert.Equal(t, "land-conflict-auto-recovered", store.events[0].Kind)
}

func TestAttempt_ConflictUnresolvable_ReturnsPark(t *testing.T) {
	store := &attemptStore{}
	target := bead.Bead{ID: "ddx-test"}

	out, err := Attempt(context.Background(), store, target.ID, AttemptOpts{
		Bead: target,
		Executor: ExecutorFunc(func(ctx context.Context, beadID string) (Report, error) {
			return Report{
				BeadID:      beadID,
				Status:      StatusLandConflict,
				Detail:      "merge conflict",
				PreserveRef: "refs/ddx/iterations/ddx-test/attempt",
				BaseRev:     "base",
				ResultRev:   "result",
				SessionID:   "session",
			}, nil
		}),
		Store:       store,
		ProjectRoot: t.TempDir(),
		AutoRecover: func(wd, preserveRef string) (string, error) {
			return "", fmt.Errorf("cannot auto-merge")
		},
		Assignee: "worker",
		Now:      func() time.Time { return time.Date(2026, 5, 4, 1, 2, 3, 0, time.UTC) },
		Cooldown: 15 * time.Minute,
	})
	require.NoError(t, err)

	assert.Equal(t, OutcomePark, out.Disposition)
	assert.Equal(t, StatusLandConflictUnresolvable, out.Report.Status)
	assert.True(t, store.unclaimed)
	assert.Equal(t, StatusLandConflictUnresolvable, store.cooldownStatus)
